-- DMT_V_AR_LINES_DETAIL
CREATE OR REPLACE EDITIONABLE VIEW "DMT_V_AR_LINES_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "TRX_NUMBER", "LINE_TYPE", "ORG_ID", "BATCH_SOURCE_NAME", "CUST_TRX_TYPE_NAME", "TERM_NAME", "TRX_DATE", "GL_DATE", "ORIG_SYSTEM_BILL_CUSTOMER_REF", "ORIG_SYSTEM_BILL_ADDRESS_REF", "ORIG_SYSTEM_BILL_CONTACT_REF", "ORIG_SYS_SHIP_PARTY_REF", "ORIG_SYS_SHIP_PARTY_SITE_REF", "ORIG_SYS_SHIP_PTY_CONTACT_REF", "ORIG_SYSTEM_SHIP_CUSTOMER_REF", "ORIG_SYSTEM_SHIP_ADDRESS_REF", "ORIG_SYSTEM_SHIP_CONTACT_REF", "ORIG_SYS_SOLD_PARTY_REF", "ORIG_SYSTEM_SOLD_CUSTOMER_REF", "BILL_CUSTOMER_ACCOUNT_NUMBER", "BILL_CUSTOMER_SITE_NUMBER", "BILL_CONTACT_PARTY_NUMBER", "SHIP_CUSTOMER_ACCOUNT_NUMBER", "SHIP_CUSTOMER_SITE_NUMBER", "SHIP_CONTACT_PARTY_NUMBER", "SOLD_CUSTOMER_ACCOUNT_NUMBER", "DESCRIPTION", "CURRENCY_CODE", "CONVERSION_TYPE", "CONVERSION_DATE", "CONVERSION_RATE", "AMOUNT", "QUANTITY", "QUANTITY_ORDERED", "UNIT_SELLING_PRICE", "UNIT_STANDARD_PRICE", "INTERFACE_LINE_CONTEXT", "INTERFACE_LINE_ATTRIBUTE1", "INTERFACE_LINE_ATTRIBUTE2", "INTERFACE_LINE_ATTRIBUTE3", "INTERFACE_LINE_ATTRIBUTE4", "INTERFACE_LINE_ATTRIBUTE5", "INTERFACE_LINE_ATTRIBUTE6", "INTERFACE_LINE_ATTRIBUTE7", "INTERFACE_LINE_ATTRIBUTE8", "INTERFACE_LINE_ATTRIBUTE9", "INTERFACE_LINE_ATTRIBUTE10", "INTERFACE_LINE_ATTRIBUTE11", "INTERFACE_LINE_ATTRIBUTE12", "INTERFACE_LINE_ATTRIBUTE13", "INTERFACE_LINE_ATTRIBUTE14", "INTERFACE_LINE_ATTRIBUTE15", "PRIMARY_SALESREP_NUMBER", "TAX_CODE", "LEGAL_ENTITY_IDENTIFIER", "ACCTD_AMOUNT", "SALES_ORDER", "SALES_ORDER_DATE", "SHIP_DATE_ACTUAL", "WAREHOUSE_CODE", "UOM_CODE", "UOM_NAME", "INVOICING_RULE_NAME", "ACCOUNTING_RULE_NAME", "ACCOUNTING_RULE_DURATION", "RULE_START_DATE", "RULE_END_DATE", "REASON_CODE_MEANING", "LAST_PERIOD_TO_CREDIT", "TRX_BUSINESS_CATEGORY", "PRODUCT_FISC_CLASSIFICATION", "PRODUCT_CATEGORY", "PRODUCT_TYPE", "LINE_INTENDED_USE", "ASSESSABLE_VALUE", "DOCUMENT_SUB_TYPE", "DEFAULT_TAXATION_COUNTRY", "USER_DEFINED_FISC_CLASS", "TAX_INVOICE_NUMBER", "TAX_INVOICE_DATE", "TAX_REGIME_CODE", "TAX", "TAX_STATUS_CODE", "TAX_RATE_CODE", "TAX_JURISDICTION_CODE", "FIRST_PTY_REG_NUM", "THIRD_PTY_REG_NUM", "FINAL_DISCHARGE_LOCATION_CODE", "TAXABLE_AMOUNT", "TAXABLE_FLAG", "TAX_EXEMPT_FLAG", "TAX_EXEMPT_REASON_CODE", "TAX_EXEMPT_REASON_CODE_MEANING", "TAX_EXEMPT_NUMBER", "AMOUNT_INCLUDES_TAX_FLAG", "TAX_PRECEDENCE", "CREDIT_METHOD_FOR_ACCT_RULE", "CREDIT_METHOD_FOR_INSTALLMENTS", "REASON_CODE", "TAX_RATE", "FOB_POINT", "SHIP_VIA", "WAYBILL_NUMBER", "SALES_ORDER_LINE", "SALES_ORDER_SOURCE", "SALES_ORDER_REVISION", "PURCHASE_ORDER", "PURCHASE_ORDER_REVISION", "PURCHASE_ORDER_DATE", "AGREEMENT_NAME", "MEMO_LINE_NAME", "DOCUMENT_NUMBER", "ORIG_SYSTEM_BATCH_NAME", "LINK_TO_LINE_CONTEXT", "LINK_TO_LINE_ATTRIBUTE1", "LINK_TO_LINE_ATTRIBUTE2", "LINK_TO_LINE_ATTRIBUTE3", "LINK_TO_LINE_ATTRIBUTE4", "LINK_TO_LINE_ATTRIBUTE5", "LINK_TO_LINE_ATTRIBUTE6", "RECEIPT_METHOD_NAME", "PRINTING_OPTION", "RELATED_BATCH_SOURCE_NAME", "RELATED_TRX_NUMBER", "TRANSLATED_DESCRIPTION", "CONS_BILLING_NUMBER", "PROMISED_COMMITMENT_AMOUNT", "PAYMENT_SET_ID", "ORIGINAL_GL_DATE", "INVOICED_LINE_ACCTG_LEVEL", "OVERRIDE_AUTO_ACCOUNTING_FLAG", "HISTORICAL_FLAG", "DEFERRAL_EXCLUSION_FLAG", "BILLING_DATE", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "HEADER_ATTRIBUTE_CATEGORY", "HEADER_ATTRIBUTE1", "HEADER_ATTRIBUTE2", "HEADER_ATTRIBUTE3", "HEADER_ATTRIBUTE4", "HEADER_ATTRIBUTE5", "HEADER_ATTRIBUTE6", "HEADER_ATTRIBUTE7", "HEADER_ATTRIBUTE8", "HEADER_ATTRIBUTE9", "HEADER_ATTRIBUTE10", "HEADER_ATTRIBUTE11", "HEADER_ATTRIBUTE12", "HEADER_ATTRIBUTE13", "HEADER_ATTRIBUTE14", "HEADER_ATTRIBUTE15", "BU_NAME", "COMMENTS", "INTERNAL_NOTES", "RESET_TRX_DATE_FLAG", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    -- 1. Run status
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    -- 2. Error text
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    -- 3. Human identifiers
    stg.TRX_NUMBER                                          AS TRX_NUMBER,
    stg.LINE_TYPE                                           AS LINE_TYPE,
    -- 4. All remaining STG business columns
    stg.ORG_ID,
    stg.BATCH_SOURCE_NAME,
    stg.CUST_TRX_TYPE_NAME,
    stg.TERM_NAME,
    stg.TRX_DATE,
    stg.GL_DATE,
    stg.ORIG_SYSTEM_BILL_CUSTOMER_REF,
    stg.ORIG_SYSTEM_BILL_ADDRESS_REF,
    stg.ORIG_SYSTEM_BILL_CONTACT_REF,
    stg.ORIG_SYS_SHIP_PARTY_REF,
    stg.ORIG_SYS_SHIP_PARTY_SITE_REF,
    stg.ORIG_SYS_SHIP_PTY_CONTACT_REF,
    stg.ORIG_SYSTEM_SHIP_CUSTOMER_REF,
    stg.ORIG_SYSTEM_SHIP_ADDRESS_REF,
    stg.ORIG_SYSTEM_SHIP_CONTACT_REF,
    stg.ORIG_SYS_SOLD_PARTY_REF,
    stg.ORIG_SYSTEM_SOLD_CUSTOMER_REF,
    stg.BILL_CUSTOMER_ACCOUNT_NUMBER,
    stg.BILL_CUSTOMER_SITE_NUMBER,
    stg.BILL_CONTACT_PARTY_NUMBER,
    stg.SHIP_CUSTOMER_ACCOUNT_NUMBER,
    stg.SHIP_CUSTOMER_SITE_NUMBER,
    stg.SHIP_CONTACT_PARTY_NUMBER,
    stg.SOLD_CUSTOMER_ACCOUNT_NUMBER,
    stg.DESCRIPTION,
    stg.CURRENCY_CODE,
    stg.CONVERSION_TYPE,
    stg.CONVERSION_DATE,
    stg.CONVERSION_RATE,
    stg.AMOUNT,
    stg.QUANTITY,
    stg.QUANTITY_ORDERED,
    stg.UNIT_SELLING_PRICE,
    stg.UNIT_STANDARD_PRICE,
    stg.INTERFACE_LINE_CONTEXT,
    stg.INTERFACE_LINE_ATTRIBUTE1,
    stg.INTERFACE_LINE_ATTRIBUTE2,
    stg.INTERFACE_LINE_ATTRIBUTE3,
    stg.INTERFACE_LINE_ATTRIBUTE4,
    stg.INTERFACE_LINE_ATTRIBUTE5,
    stg.INTERFACE_LINE_ATTRIBUTE6,
    stg.INTERFACE_LINE_ATTRIBUTE7,
    stg.INTERFACE_LINE_ATTRIBUTE8,
    stg.INTERFACE_LINE_ATTRIBUTE9,
    stg.INTERFACE_LINE_ATTRIBUTE10,
    stg.INTERFACE_LINE_ATTRIBUTE11,
    stg.INTERFACE_LINE_ATTRIBUTE12,
    stg.INTERFACE_LINE_ATTRIBUTE13,
    stg.INTERFACE_LINE_ATTRIBUTE14,
    stg.INTERFACE_LINE_ATTRIBUTE15,
    stg.PRIMARY_SALESREP_NUMBER,
    stg.TAX_CODE,
    stg.LEGAL_ENTITY_IDENTIFIER,
    stg.ACCTD_AMOUNT,
    stg.SALES_ORDER,
    stg.SALES_ORDER_DATE,
    stg.SHIP_DATE_ACTUAL,
    stg.WAREHOUSE_CODE,
    stg.UOM_CODE,
    stg.UOM_NAME,
    stg.INVOICING_RULE_NAME,
    stg.ACCOUNTING_RULE_NAME,
    stg.ACCOUNTING_RULE_DURATION,
    stg.RULE_START_DATE,
    stg.RULE_END_DATE,
    stg.REASON_CODE_MEANING,
    stg.LAST_PERIOD_TO_CREDIT,
    stg.TRX_BUSINESS_CATEGORY,
    stg.PRODUCT_FISC_CLASSIFICATION,
    stg.PRODUCT_CATEGORY,
    stg.PRODUCT_TYPE,
    stg.LINE_INTENDED_USE,
    stg.ASSESSABLE_VALUE,
    stg.DOCUMENT_SUB_TYPE,
    stg.DEFAULT_TAXATION_COUNTRY,
    stg.USER_DEFINED_FISC_CLASS,
    stg.TAX_INVOICE_NUMBER,
    stg.TAX_INVOICE_DATE,
    stg.TAX_REGIME_CODE,
    stg.TAX,
    stg.TAX_STATUS_CODE,
    stg.TAX_RATE_CODE,
    stg.TAX_JURISDICTION_CODE,
    stg.FIRST_PTY_REG_NUM,
    stg.THIRD_PTY_REG_NUM,
    stg.FINAL_DISCHARGE_LOCATION_CODE,
    stg.TAXABLE_AMOUNT,
    stg.TAXABLE_FLAG,
    stg.TAX_EXEMPT_FLAG,
    stg.TAX_EXEMPT_REASON_CODE,
    stg.TAX_EXEMPT_REASON_CODE_MEANING,
    stg.TAX_EXEMPT_NUMBER,
    stg.AMOUNT_INCLUDES_TAX_FLAG,
    stg.TAX_PRECEDENCE,
    stg.CREDIT_METHOD_FOR_ACCT_RULE,
    stg.CREDIT_METHOD_FOR_INSTALLMENTS,
    stg.REASON_CODE,
    stg.TAX_RATE,
    stg.FOB_POINT,
    stg.SHIP_VIA,
    stg.WAYBILL_NUMBER,
    stg.SALES_ORDER_LINE,
    stg.SALES_ORDER_SOURCE,
    stg.SALES_ORDER_REVISION,
    stg.PURCHASE_ORDER,
    stg.PURCHASE_ORDER_REVISION,
    stg.PURCHASE_ORDER_DATE,
    stg.AGREEMENT_NAME,
    stg.MEMO_LINE_NAME,
    stg.DOCUMENT_NUMBER,
    stg.ORIG_SYSTEM_BATCH_NAME,
    stg.LINK_TO_LINE_CONTEXT,
    stg.LINK_TO_LINE_ATTRIBUTE1,
    stg.LINK_TO_LINE_ATTRIBUTE2,
    stg.LINK_TO_LINE_ATTRIBUTE3,
    stg.LINK_TO_LINE_ATTRIBUTE4,
    stg.LINK_TO_LINE_ATTRIBUTE5,
    stg.LINK_TO_LINE_ATTRIBUTE6,
    stg.RECEIPT_METHOD_NAME,
    stg.PRINTING_OPTION,
    stg.RELATED_BATCH_SOURCE_NAME,
    stg.RELATED_TRX_NUMBER,
    stg.TRANSLATED_DESCRIPTION,
    stg.CONS_BILLING_NUMBER,
    stg.PROMISED_COMMITMENT_AMOUNT,
    stg.PAYMENT_SET_ID,
    stg.ORIGINAL_GL_DATE,
    stg.INVOICED_LINE_ACCTG_LEVEL,
    stg.OVERRIDE_AUTO_ACCOUNTING_FLAG,
    stg.HISTORICAL_FLAG,
    stg.DEFERRAL_EXCLUSION_FLAG,
    stg.BILLING_DATE,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.HEADER_ATTRIBUTE_CATEGORY,
    stg.HEADER_ATTRIBUTE1,
    stg.HEADER_ATTRIBUTE2,
    stg.HEADER_ATTRIBUTE3,
    stg.HEADER_ATTRIBUTE4,
    stg.HEADER_ATTRIBUTE5,
    stg.HEADER_ATTRIBUTE6,
    stg.HEADER_ATTRIBUTE7,
    stg.HEADER_ATTRIBUTE8,
    stg.HEADER_ATTRIBUTE9,
    stg.HEADER_ATTRIBUTE10,
    stg.HEADER_ATTRIBUTE11,
    stg.HEADER_ATTRIBUTE12,
    stg.HEADER_ATTRIBUTE13,
    stg.HEADER_ATTRIBUTE14,
    stg.HEADER_ATTRIBUTE15,
    stg.BU_NAME,
    stg.COMMENTS,
    stg.INTERNAL_NOTES,
    stg.RESET_TRX_DATE_FLAG,
    stg.SOURCE_ID,
    -- 5. STG_SEQUENCE_ID
    stg.STG_SEQUENCE_ID,
    -- 6. RUN_ID
    tfm.RUN_ID,
    -- 7. PREFIX (from PIPELINE_RUN)
    cm.PREFIX,
    -- 8. SCENARIO_ID
    stg.SCENARIO_ID,
    -- 9. STAGE_DATE
    stg.STAGE_DATE,
    -- 10. LAST_UPDATED_DATE
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_RA_LINES_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_RA_LINES_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
